use std::fs;
use std::collections::HashMap;

static mut CACHE: Option<HashMap<String, String>> = None;

pub fn handle_request(path: &str, body: &str) -> String {
    let content = fs::read_to_string(path).unwrap();

    unsafe {
        if CACHE.is_none() {
            CACHE = Some(HashMap::new());
        }
        CACHE.as_mut().unwrap().insert(path.to_string(), body.to_string());
    }

    let config: serde_json::Value = serde_json::from_str(body).unwrap();
    let name = config["name"].as_str().unwrap();

    let output = format!("Hello, {}! File content: {}", name, content);
    output
}

