    q = request.args.get('q', '')
    conn = sqlite3.connect('app.db')
    results = conn.execute(f"SELECT * FROM products WHERE name LIKE '%{q}%'").fetchall()
    conn.close()
    return f"<h1>Results for {q}</h1><ul>{''.join(f'<li>{r[1]}</li>' for r in results)}</ul>"

